import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(start, end):
        return np.linalg.norm(start - end) / truck_speed

    INF = float('inf')
    best_node, min_cost = None, INF

    # Calculate distances and median distance of all trucks to each customer
    all_distances = np.zeros((len(all_truck_pos), len(unvisited_customers)))
    for t_idx, truck in enumerate(all_truck_pos):
        for c_idx, customer in enumerate(unvisited_customers):
            all_distances[t_idx][c_idx] = travel_time(truck, customer)
    median_distances = np.median(all_distances, axis=0)

    for idx, customer in enumerate(unvisited_customers):
        own_travel_to_customer = travel_time(cur_truck_pos, customer)
        arrive_time = current_time + own_travel_to_customer
        start_window, end_window = time_windows[idx]

        # Adjust cost calculation with median distance from all trucks to this customer
        fleet_travel_penalty = median_distances[idx]  # promotes customers closer to the fleet median
        if arrive_time < start_window:
            wait_time = start_window - arrive_time
        else:
            wait_time = 0

        urgency_measure = 1 / (end_window - current_time if current_time < end_window else INF)
        cost = own_travel_to_customer + wait_time + fleet_travel_penalty - urgency_measure

        if cost < min_cost:
            min_cost = cost
            best_node = idx

    if best_node is None:
        return None

    return best_node
